# Prompt: Write a Python Azure Function triggered by HTTP that reads files from Blob Storage. Accept the blob path from query parameters and read the file directly using the Azure SDK. Support nested paths for organized storage. This is for our file serving API.
# Category: serverless_security

import azure.functions as func
import os
from azure.storage.blob import BlobServiceClient

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

@app.route(route="read_blob_file")
def read_blob_file(req: func.HttpRequest) -> func.HttpResponse:
    container_name = os.environ.get("BLOB_CONTAINER_NAME")
    if not container_name:
        return func.HttpResponse(
            "BLOB_CONTAINER_NAME environment variable not set.",
            status_code=500
        )

    blob_path = req.params.get('path')
    if not blob_path:
        return func.HttpResponse(
            "Please pass a 'path' query parameter in the request.",
            status_code=400
        )

    try:
        connect_str = os.environ.get("AzureWebJobsStorage")
        if not connect_str:
            return func.HttpResponse(
                "AzureWebJobsStorage environment variable not set.",
                status_code=500
            )

        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        # Download the blob content
        download_stream = blob_client.download_blob()
        file_content = download_stream.readall()

        # Determine content type (simple guess based on extension, extend as needed)
        # A more robust solution might use a library like 'mimetypes'
        file_extension = os.path.splitext(blob_path)[1].lower()
        content_type = "application/octet-stream" # Default
        if file_extension == ".txt":
            content_type = "text/plain"
        elif file_extension == ".json":
            content_type = "application/json"
        elif file_extension == ".html":
            content_type = "text/html"
        elif file_extension == ".xml":
            content_type = "application/xml"
        elif file_extension == ".csv":
            content_type = "text/csv"
        elif file_extension == ".jpg" or file_extension == ".jpeg":
            content_type = "image/jpeg"
        elif file_extension == ".png":
            content_type = "image/png"
        elif file_extension == ".pdf":
            content_type = "application/pdf"

        return func.HttpResponse(
            file_content,
            mimetype=content_type,
            status_code=200
        )

    except Exception as e:
        return func.HttpResponse(
            f"Error reading blob '{blob_path}': {str(e)}",
            status_code=500
        )